    "titleZh": "Introduction to Machine Learning",
    "credits": 6,
    "recommendedYear": 2,
    "semester": "1 / 2",
    "courseType": "major_elective",
    "prerequisites": "COMP2118 or COMP2119 or COMP2502 or ELEC2543 or FITE2000; and MATH1013 or MATH1853 or MATH2014",
    "exclusions": "None",
    "description": "This course introduces algorithms, tools, practices, and applications of machine learning. Topics include core methods such as supervised learning (classification and regression), unsupervised learning (clustering, principal component analysis), Bayesian estimation, neural networks; common practices in data pre-processing, hyper-parameter tuning, and model evaluation; tools/libraries/APIs such as scikit-learn, Theano/Keras, and multi/many-core CPU/GPU programming.",
    "sourceUrl": "https://www.cs.hku.hk/index.php/programmes/course-offered?infile=2025/comp3314.html",
