    "credits": 6,
    "recommendedYear": 4,
    "semester": "2",
    "courseType": "capstone",
    "prerequisites": "None",
    "exclusions": "COMP4501",
    "description": "In this final year capstone project, students are required to initiate project ideas, develop feasible and effective solutions, and produce a comprehensive final deliverable. Project topics may cover diverse areas, including applied software development, practical and innovative solutions to everyday challenges, and basic research. The deliverables must demonstrate a thorough integration of the students’ computing expertise and skills. Each project team member must make significant contributions, and individual assessments will be conducted for all students.",
    "sourceUrl": "https://www.cs.hku.hk/index.php/programmes/course-offered?infile=2025/comp4502.html",
